        boolean carry = true; // add 1 to lowest order part.
        boolean maxIndex = true;
        for (int testPartsIndexIndex = testPartsIndex.length - 1;
                testPartsIndexIndex >= 0;
                --testPartsIndexIndex) {
            int index = testPartsIndex[testPartsIndexIndex];
